(236, 'Discord', 'Broadblade', 4, 'Energy Regen%', 'wp_discord.png', 'When Resonance Skill is cast, restores [8, 2] Concerto Energy. This effect can be triggered 1 time(s) every 20s.', 'A descending adagio. This broadblade dominates the battlefield with the power of discordance. The curtain never falls on a masterpiece.', 27, 337, '11.52%', '51.84%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Ceaseless Aria'),
(237, 'Overture', 'Sword', 4, 'Energy Regen%', 'wp_overture.png', 'When Resonance Skill is cast, restores [8, 2] Concerto Energy. This effect can be triggered 1 time(s) every 20s.', 'An ascending crescendo. This enchanting sword effortlessly cuts through anything in its way, like a glorious prelude.', 27, 337, '11.52%', '51.84%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Ceaseless Aria'),
(238, 'Cadenza', 'Pistols', 4, 'Energy Regen%', 'wp_cadenza.png', 'When Resonance Skill is cast, restores [8, 2] Concerto Energy. This effect can be triggered 1 times every 20s.', 'An ascending crescendo. These pistols unleash bullets with the force of thunder, tearing through the heavens like a symphony of destruction.', 27, 337, '11.52%', '51.84%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Ceaseless Aria'),
